475: void UpstreamRequest::resetStream() {
476:   if (conn_pool_->cancelAnyPendingStream()) {
477:     ENVOY_STREAM_LOG(debug, "canceled pool request", *parent_.callbacks());
478:     ASSERT(!upstream_);
479:   }
480: 
481:   // Don't reset the stream if we're already done with it.
482:   if (upstreamTiming().last_upstream_tx_byte_sent_.has_value() &&
483:       upstreamTiming().last_upstream_rx_byte_received_.has_value()) {
484:     return;
485:   }
486: 
487:   if (span_ != nullptr) {
488:     // Add tags about the cancellation.
489:     span_->setTag(Tracing::Tags::get().Canceled, Tracing::Tags::get().True);
490:   }
491: 
492:   if (upstream_) {
493:     ENVOY_STREAM_LOG(debug, "resetting pool request", *parent_.callbacks());
494:     upstream_->resetStream();
495:     clearRequestEncoder();
496:   }
497:   reset_stream_ = true;
498: }
