1455: Filter::streamResetReasonToResponseFlag(Http::StreamResetReason reset_reason) {
1456:   switch (reset_reason) {
1457:   case Http::StreamResetReason::LocalConnectionFailure:
1458:   case Http::StreamResetReason::RemoteConnectionFailure:
1459:   case Http::StreamResetReason::ConnectionTimeout:
1460:     return StreamInfo::CoreResponseFlag::UpstreamConnectionFailure;
1461:   case Http::StreamResetReason::ConnectionTermination:
1462:     return StreamInfo::CoreResponseFlag::UpstreamConnectionTermination;
1463:   case Http::StreamResetReason::LocalReset:
1464:   case Http::StreamResetReason::LocalRefusedStreamReset:
1465:     return StreamInfo::CoreResponseFlag::LocalReset;
1466:   case Http::StreamResetReason::Overflow:
1467:     return StreamInfo::CoreResponseFlag::UpstreamOverflow;
1468:   case Http::StreamResetReason::RemoteReset:
1469:   case Http::StreamResetReason::RemoteRefusedStreamReset:
1470:   case Http::StreamResetReason::ConnectError:
1471:     return StreamInfo::CoreResponseFlag::UpstreamRemoteReset;
1472:   case Http::StreamResetReason::ProtocolError:
1473:     return StreamInfo::CoreResponseFlag::UpstreamProtocolError;
1474:   case Http::StreamResetReason::OverloadManager:
1475:     return StreamInfo::CoreResponseFlag::OverloadManager;
1476:   }
1477: 
1478:   PANIC_DUE_TO_CORRUPT_ENUM;
