1481: void Filter::handleNon5xxResponseHeaders(absl::optional<Grpc::Status::GrpcStatus> grpc_status,
1482:                                          UpstreamRequest& upstream_request, bool end_stream,
1483:                                          uint64_t grpc_to_http_status) {
1484:   // We need to defer gRPC success until after we have processed grpc-status in
1485:   // the trailers.
1486:   if (grpc_request_) {
1487:     if (end_stream) {
1488:       if (grpc_status && !Http::CodeUtility::is5xx(grpc_to_http_status)) {
1489:         upstream_request.upstreamHost()->stats().rq_success_.inc();
1490:       } else {
1491:         upstream_request.upstreamHost()->stats().rq_error_.inc();
1492:       }
1493:     } else {
1494:       upstream_request.grpcRqSuccessDeferred(true);
1495:     }
1496:   } else {
1497:     upstream_request.upstreamHost()->stats().rq_success_.inc();
1498:   }
1499: }
